local cjson = require "cjson"
local redis = require "resty.redis"

-- Configuration
local REDIS_HOST = os.getenv("REDIS_HOST") or "127.0.0.1"
local REDIS_PORT = tonumber(os.getenv("REDIS_PORT")) or 6379
local REDIS_PASSWORD = os.getenv("REDIS_PASSWORD") or nil
local REDIS_TIMEOUT = 5000
local REDIS_PLUGIN_PREFIX = "gateway:plugin:"

-- Plugin cache (shared dict must be defined in nginx.conf: lua_shared_dict plugin_cache 10m;)
local plugin_cache = ngx.shared.plugin_cache
local CACHE_TTL = 60 -- seconds

-- Sandbox environment for plugin execution
local function create_sandbox_env()
    return {
        -- Safe builtins
        string = string,
        table = table,
        math = math,
        tonumber = tonumber,
        tostring = tostring,
        type = type,
        pairs = pairs,
        ipairs = ipairs,
        next = next,
        select = select,
        unpack = unpack or table.unpack,
        pcall = pcall,
        xpcall = xpcall,
        error = error,
        assert = assert,

        -- Ngx API (read/safe operations)
        ngx = {
            log = ngx.log,
            ERR = ngx.ERR,
            WARN = ngx.WARN,
            INFO = ngx.INFO,
            DEBUG = ngx.DEBUG,
            say = ngx.say,
            print = ngx.print,
            exit = ngx.exit,
            status = ngx.status,
            header = ngx.header,
            req = {
                get_headers = ngx.req.get_headers,
                get_method = ngx.req.get_method,
                get_uri_args = ngx.req.get_uri_args,
                read_body = ngx.req.read_body,
                get_body_data = ngx.req.get_body_data,
                set_header = ngx.req.set_header,
                get_post_args = ngx.req.get_post_args,
            },
            var = ngx.var,
            ctx = ngx.ctx,
            now = ngx.now,
            time = ngx.time,
            today = ngx.today,
            http_time = ngx.http_time,
            re = ngx.re,
            encode_base64 = ngx.encode_base64,
            decode_base64 = ngx.decode_base64,
            md5 = ngx.md5,
            sha1_bin = ngx.sha1_bin,
            hmac_sha1 = ngx.hmac_sha1,
            encode_args = ngx.encode_args,
            HTTP_OK = ngx.HTTP_OK,
            HTTP_BAD_REQUEST = ngx.HTTP_BAD_REQUEST,
            HTTP_UNAUTHORIZED = ngx.HTTP_UNAUTHORIZED,
            HTTP_FORBIDDEN = ngx.HTTP_FORBIDDEN,
            HTTP_NOT_FOUND = ngx.HTTP_NOT_FOUND,
            HTTP_INTERNAL_SERVER_ERROR = ngx.HTTP_INTERNAL_SERVER_ERROR,
            HTTP_SERVICE_UNAVAILABLE = ngx.HTTP_SERVICE_UNAVAILABLE,
            shared = ngx.shared,
        },

        -- JSON support
        cjson = {
            encode = cjson.encode,
            decode = cjson.decode,
        },
    }
end

-- Connect to Redis
local function get_redis_connection()
    local red = redis:new()
    red:set_timeout(REDIS_TIMEOUT)

    local ok, err = red:connect(REDIS_HOST, REDIS_PORT)
    if not ok then
        ngx.log(ngx.ERR, "Failed to connect to Redis: ", err)
        return nil, err
    end

    if REDIS_PASSWORD then
        local ok, err = red:auth(REDIS_PASSWORD)
        if not ok then
            ngx.log(ngx.ERR, "Failed to authenticate with Redis: ", err)
            return nil, err
        end
    end

    return red
end

-- Return Redis connection to pool
local function release_redis_connection(red)
    if not red then return end
    local ok, err = red:set_keepalive(10000, 100)
    if not ok then
        ngx.log(ngx.WARN, "Failed to set Redis keepalive: ", err)
    end
end

-- Load plugin code from Redis by plugin name
local function load_plugin_from_redis(plugin_name)
    -- Check local cache first
    local cached_code = plugin_cache:get(plugin_name)
    if cached_code then
        ngx.log(ngx.DEBUG, "Plugin '", plugin_name, "' loaded from cache")
        return cached_code
    end

    local red, err = get_redis_connection()
    if not red then
        return nil, "Redis connection failed: " .. (err or "unknown")
    end

    local key = REDIS_PLUGIN_PREFIX .. plugin_name
    local code, err = red:get(key)
    release_redis_connection(red)

    if not code or code == ngx.null then
        return nil, "Plugin '" .. plugin_name .. "' not found in Redis"
    end

    -- Cache the plugin code
    plugin_cache:set(plugin_name, code, CACHE_TTL)
    ngx.log(ngx.INFO, "Plugin '", plugin_name, "' loaded from Redis and cached")

    return code
end

-- Load all plugin metadata from Redis
local function list_plugins_from_redis()
    local red, err = get_redis_connection()
    if not red then
        return nil, "Redis connection failed: " .. (err or "unknown")
    end

    local keys, err = red:keys(REDIS_PLUGIN_PREFIX .. "*")
    release_redis_connection(red)

    if not keys or keys == ngx.null then
        return {}
    end

    local plugins = {}
    local prefix_len = #REDIS_PLUGIN_PREFIX
    for _, key in ipairs(keys) do
        table.insert(plugins, string.sub(key, prefix_len + 1))
    end

    return plugins
end

-- Store plugin code into Redis
local function store_plugin_to_redis(plugin_name, code)
    local red, err = get_redis_connection()
    if not red then
        return nil, "Redis connection failed: " .. (err or "unknown")
    end

    local key = REDIS_PLUGIN_PREFIX .. plugin_name
    local ok, err = red:set(key, code)
    release_redis_connection(red)

    if not ok then
        return nil, "Failed to store plugin: " .. (err or "unknown")
    end

    -- Invalidate cache
    plugin_cache:delete(plugin_name)
    ngx.log(ngx.INFO, "Plugin '", plugin_name, "' stored to Redis")

    return true
end

-- Delete plugin from Redis
local function delete_plugin_from_redis(plugin_name)
    local red, err = get_redis_connection()
    if not red then
        return nil, "Redis connection failed: " .. (err or "unknown")
    end

    local key = REDIS_PLUGIN_PREFIX .. plugin_name
    local ok, err = red:del(key)
    release_redis_connection(red)

    if not ok then
        return nil, "Failed to delete plugin: " .. (err or "unknown")
    end

    -- Invalidate cache
    plugin_cache:delete(plugin_name)
    ngx.log(ngx.INFO, "Plugin '", plugin_name, "' deleted from Redis")

    return true
end

-- Compile and execute plugin code in sandboxed environment
local function execute_plugin(code, plugin_name, context)
    plugin_name = plugin_name or "anonymous"

    -- Compile the code
    local load_fn = load or loadstring
    local chunk, compile_err = load_fn(code, "=" .. plugin_name)
    if not chunk then
        return nil, "Compilation error in plugin '" .. plugin_name .. "': " .. (compile_err or "unknown")
    end

    -- Create sandbox environment
    local sandbox = create_sandbox_env()

    -- Inject the execution context into the sandbox
    sandbox.context = context or {}
    sandbox.plugin_name = plugin_name

    -- Set the sandbox as the function's environment
    if setfenv then
        -- Lua 5.1 / LuaJIT
        setfenv(chunk, sandbox)
    else
        -- Lua 5.2+ uses upvalues; load with env
        chunk, compile_err = load(code, "=" .. plugin_name, "t", sandbox)
        if not chunk then
            return nil, "Compilation error in plugin '" .. plugin_name .. "': " .. (compile_err or "unknown")
        end
    end

    -- Execute with pcall for safety
    local ok, result = pcall(chunk)
    if not ok then
        return nil, "Runtime error in plugin '" .. plugin_name .. "': " .. tostring(result)
    end

    return result
end

-- Execute a plugin chain (multiple plugins in sequence)
local function execute_plugin_chain(plugin_names, context)
    context = context or {}
    context.chain_results = {}

    for i, plugin_name in ipairs(plugin_names) do
        local code, err = load_plugin_from_redis(plugin_name)
        if not code then
            ngx.log(ngx.ERR, "Plugin chain: failed to load '", plugin_name, "': ", err)
            return nil, err
        end

        local result, exec_err = execute_plugin(code, plugin_name, context)
        if exec_err then
            ngx.log(ngx.ERR, "Plugin chain: execution failed for '", plugin_name, "': ", exec_err)
            return nil, exec_err
        end

        context.chain_results[plugin_name] = result

        -- If plugin returns false or sets context.stop_chain, stop execution
        if result == false or context.stop_chain then
            ngx.log(ngx.INFO, "Plugin chain stopped by '", plugin_name, "'")
            break
        end
    end

    return context.chain_results
end

-- Build request context for plugins
local function build_request_context()
    ngx.req.read_body()
    return {
        method = ngx.req.get_method(),
        uri = ngx.var.uri,
        args = ngx.req.get_uri_args(),
        headers = ngx.req.get_headers(),
        body = ngx.req.get_body_data(),
        remote_addr = ngx.var.remote_addr,
        server_name = ngx.var.server_name,
        request_time = ngx.now(),
    }
end

-- JSON response helper
local function json_response(status, data)
    ngx.status = status
    ngx.header["Content-Type"] = "application/json"
    ngx.say(cjson.encode(data))
    return ngx.exit(status)
end

-- ========================================
-- Main request handling
-- ========================================

local function handle_request()
    local method = ngx.req.get_method()
    local uri = ngx.var.uri

    -- ---- Admin API for plugin management ----

    -- POST /plugins/:name - Register a new plugin
    local plugin_name = string.match(uri, "^/plugins/([%w_%-%.]+)$")
    if plugin_name and method == "POST" then
        ngx.req.read_body()
        local body = ngx.req.get_body_data()
        if not body or body == "" then
            return json_response(400, { error = "Plugin code is required in request body" })
        end

        -- Validate: try to compile the code first
        local load_fn = load or loadstring
        local chunk, compile_err = load_fn(body, "=" .. plugin_name)
        if not chunk then
            return json_response(400, {
                error = "Plugin code compilation failed",
                details = compile_err
            })
        end

        local ok, err = store_plugin_to_redis(plugin_name, body)
        if not ok then
            return json_response(500, { error = "Failed to store plugin", details = err })
        end

        return json_response(201, {
            message = "Plugin '" .. plugin_name .. "' registered successfully",
            name = plugin_name
        })
    end

    -- DELETE /plugins/:name - Remove a plugin
    if plugin_name and method == "DELETE" then
        local ok, err = delete_plugin_from_redis(plugin_name)
        if not ok then
            return json_response(500, { error = "Failed to delete plugin", details = err })
        end
        return json_response(200, { message = "Plugin '" .. plugin_name .. "' deleted" })
    end

    -- GET /plugins/:name - Get plugin code
    if plugin_name and method == "GET" then
        local code, err = load_plugin_from_redis(plugin_name)
        if not code then
            return json_response(404, { error = err })
        end
        return json_response(200, { name = plugin_name, code = code })
    end

    -- GET /plugins - List all plugins
    if uri == "/plugins" and method == "GET" then
        local plugins, err = list_plugins_from_redis()
        if not plugins then
            return json_response(500, { error = "Failed to list plugins", details = err })
        end
        return json_response(200, { plugins = plugins })
    end

    -- ---- Plugin Execution Endpoints ----

    -- POST /execute/:name - Execute a specific plugin from Redis
    local exec_name = string.match(uri, "^/execute/([%w_%-%.]+)$")
    if exec_name and method == "POST" then
        local code, err = load_plugin_from_redis(exec_name)
        if not code then
            return json_response(404, { error = err })
        end

        local context = build_request_context()
        local result, exec_err = execute_plugin(code, exec_name, context)
        if exec_err then
            return json_response(500, { error = exec_err })
        end

        return json_response(200, {
            plugin = exec_name,
            result = result
        })
    end

    -- POST /execute-chain - Execute a chain of plugins
    if uri == "/execute-chain" and method == "POST" then
        ngx.req.read_body()
        local body = ngx.req.get_body_data()
        if not body then
            return json_response(400, { error = "Request body with plugin chain required" })
        end

        local ok_decode, chain_config = pcall(cjson.decode, body)
        if not ok_decode or not chain_config.plugins then
            return json_response(400, { error = "Invalid JSON. Expected: {\"plugins\": [\"plugin1\", \"plugin2\"]}" })
        end

        local context = build_request_context()
        -- Merge any extra context from the request
        if chain_config.context then
            for k, v in pairs(chain_config.context) do
                context[k] = v
            end
        end

        local results, err = execute_plugin_chain(chain_config.plugins, context)
        if not results then
            return json_response(500, { error = err })
        end

        return json_response(200, {
            chain = chain_config.plugins,
            results = results
        })
    end

    -- POST /execute-inline - Execute plugin code from request body directly
    if uri == "/execute-inline" and method == "POST" then
        ngx.req.read_body()
        local body = ngx.req.get_body_data()
        if not body then
            return json_response(400, { error = "Plugin code required in request body" })
        end

        local context = build_request_context()
        local result, exec_err = execute_plugin(body, "inline", context)
        if exec_err then
            return json_response(500, { error = exec_err })
        end

        return json_response(200, { result = result })
    end

    -- ---- Header-based Plugin Execution ----
    -- Execute plugin code passed via X-Plugin-Code header
    -- or execute a registered plugin via X-Plugin-Name header

    local header_plugin_code = ngx.req.get_headers()["X-Plugin-Code"]
    local header_plugin_name = ngx.req.get_headers()["X-Plugin-Name"]
    local header_plugin_chain = ngx.req.get_headers()["X-Plugin-Chain"]

    if header_plugin_code then
        -- Decode base64-encoded plugin code from header
        local decoded_code = ngx.decode_base64(header_plugin_code)
        if not decoded_code then
            return json_response(400, { error = "X-Plugin-Code header must be base64-encoded Lua code" })
        end

        local context = build_request_context()
        local result, exec_err = execute_plugin(decoded_code, "header-inline", context)
        if exec_err then
            return json_response(500, { error = exec_err })
        end

        return json_response(200, { source = "header-inline", result = result })
    end

    if header_plugin_name then
        local code, err = load_plugin_from_redis(header_plugin_name)
        if not code then
            return json_response(404, { error = err })
        end

        local context = build_request_context()
        local result, exec_err = execute_plugin(code, header_plugin_name, context)
        if exec_err then
            return json_response(500, { error = exec_err })
        end

        return json_response(200, {
            source = "header-named",
            plugin = header_plugin_name,
            result = result
        })
    end

    if header_plugin_chain then
        -- X-Plugin-Chain: plugin1,plugin2,plugin3
        local plugin_names = {}
        for name in string.gmatch(header_plugin_chain, "([%w_%-%.]+)") do
            table.insert(plugin_names, name)
        end

        if #plugin_names == 0 then
            return json_response(400, { error = "X-Plugin-Chain header must contain comma-separated plugin names" })
        end

        local context = build_request_context()
        local results, err = execute_plugin_chain(plugin_names, context)
        if not results then
            return json_response(500, { error = err })
        end

        return json_response(200, {
            source = "header-chain",
            chain = plugin_names,
            results = results
        })
    end

    -- ---- Cache Management ----

    -- POST /cache/flush - Flush the plugin cache
    if uri == "/cache/flush" and method == "POST" then
        plugin_cache:flush_all()
        return json_response(200, { message = "Plugin cache flushed" })
    end

    -- DELETE /cache/:name - Invalidate a specific plugin cache entry
    local cache_name = string.match(uri, "^/cache/([%w_%-%.]+)$")
    if cache_name and method == "DELETE" then
        plugin_cache:delete(cache_name)
        return json_response(200, { message = "Cache entry for '" .. cache_name .. "' invalidated" })
    end

    -- ---- Health Check ----
    if uri == "/health" and method == "GET" then
        local red, err = get_redis_connection()
        local redis_status = "connected"
        if not red then
            redis_status = "disconnected: " .. (err or "unknown")
        else
            release_redis_connection(red)
        end

        return json_response(200, {
            status = "healthy",
            redis = redis_status,
            cache_free = plugin_cache:free_space(),
        })
    end

    -- Default: not found
    return json_response(404, {
        error = "Not found",
        available_endpoints = {
            "GET    /health",
            "GET    /plugins",
            "GET    /plugins/:name",
            "POST   /plugins/:name",
            "DELETE /plugins/:name",
            "POST   /execute/:name",
            "POST   /execute-inline",
            "POST   /execute-chain",
            "POST   /cache/flush",
            "DELETE /cache/:name",
            "Header: X-Plugin-Name (named plugin)",
            "Header: X-Plugin-Code (base64 inline code)",
            "Header: X-Plugin-Chain (comma-separated names)",
        }
    })
end

-- Entry point
local ok, err = pcall(handle_request)
if not ok then
    ngx.log(ngx.ERR, "Gateway error: ", err)
    ngx.status = 500
    ngx.header["Content-Type"] = "application/json"
    ngx.say(cjson.encode({ error = "Internal gateway error" }))
    ngx.exit(500)
end